import React, { useEffect, useRef, useState } from 'react';
import MusicNav from './MusicNav';
import Footer from './Footer';
import './ShopPage.css';

/**
 * /shop — pulls live products + images from the Dewpoint Shopify store and
 * renders add-to-cart buttons + a cart via Shopify's Buy Button JS UI library.
 * Works on the $5 Shopify "Starter" plan (Buy Button sales channel) — no full
 * hosted storefront required.
 *
 * SETUP: In Shopify admin, add the "Buy Button" sales channel, then create a
 * Storefront API access token (Settings → Apps and sales channels → Develop
 * apps → create app → Storefront API access scopes: unauthenticated_read_
 * product_listings). Paste that token below.
 */
const SHOPIFY_DOMAIN = '233fa5.myshopify.com';
const STOREFRONT_ACCESS_TOKEN = '96ecacc6aa182703d9ed2ab602fc217b';
const BUY_BUTTON_SDK = 'https://sdks.shopifycdn.com/buy-button/latest/buy-button-storefront.min.js';

const ACCENT = '#6a4bb0';
const ACCENT_HOVER = '#5a3fa0';

// Shared styling so the Shopify-rendered components match the dark site theme.
const buyButtonOptions = {
  product: {
    iframe: true,
    contents: { img: true, title: true, price: true },
    text: { button: 'Add to cart' },
    styles: {
      product: {
        'text-align': 'center',
        '@media (min-width: 601px)': { 'max-width': '100%', 'margin-bottom': '0' },
      },
      title: { color: '#ffffff', 'font-size': '16px', 'font-weight': '600' },
      price: { color: '#d7d7ec', 'font-size': '15px' },
      compareAt: { color: '#8a8aa0' },
      button: {
        'background-color': ACCENT,
        'border-radius': '25px',
        'font-weight': '600',
        ':hover': { 'background-color': ACCENT_HOVER },
        ':focus': { 'background-color': ACCENT_HOVER },
      },
    },
  },
  cart: {
    text: { total: 'Subtotal', button: 'Checkout' },
    styles: {
      button: {
        'background-color': ACCENT,
        'border-radius': '25px',
        'font-weight': '600',
        ':hover': { 'background-color': ACCENT_HOVER },
        ':focus': { 'background-color': ACCENT_HOVER },
      },
    },
  },
  toggle: {
    styles: {
      toggle: {
        'background-color': ACCENT,
        ':hover': { 'background-color': ACCENT_HOVER },
        ':focus': { 'background-color': ACCENT_HOVER },
      },
    },
  },
};

// fetchAll() returns product ids as Storefront GIDs (gid://shopify/Product/123)
// or base64-encoded GIDs; createComponent('product') wants the bare numeric id.
const toNumericId = (raw: unknown): string => {
  let s = String(raw);
  // base64-encoded GID? (no slashes, may end with '=' padding)
  if (/^[A-Za-z0-9+/]+=*$/.test(s) && !s.includes('/')) {
    try {
      s = atob(s);
    } catch {
      /* not base64 — leave as-is */
    }
  }
  const gid = s.match(/Product\/(\d+)/);
  if (gid) return gid[1];
  const tail = s.match(/(\d+)\s*$/);
  return tail ? tail[1] : s;
};

type Status = 'loading' | 'ready' | 'empty' | 'error' | 'unconfigured';

const ShopPage: React.FC = () => {
  const gridRef = useRef<HTMLDivElement | null>(null);
  const initialized = useRef(false);
  const [status, setStatus] = useState<Status>('loading');

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    if (STOREFRONT_ACCESS_TOKEN.startsWith('REPLACE_')) {
      setStatus('unconfigured');
      return;
    }

    let cancelled = false;

    const buildStore = () => {
      const ShopifyBuy = (window as any).ShopifyBuy;
      if (!ShopifyBuy || !gridRef.current) {
        setStatus('error');
        return;
      }
      const client = ShopifyBuy.buildClient({
        domain: SHOPIFY_DOMAIN,
        storefrontAccessToken: STOREFRONT_ACCESS_TOKEN,
      });

      ShopifyBuy.UI.onReady(client)
        .then((ui: any) => client.product.fetchAll(60).then((products: any[]) => ({ ui, products })))
        .then(({ ui, products }: { ui: any; products: any[] }) => {
          if (cancelled) return;
          if (!products || products.length === 0) {
            setStatus('empty');
            return;
          }
          products.forEach((product) => {
            const node = document.createElement('div');
            node.className = 'shop-product';
            gridRef.current!.appendChild(node);
            ui.createComponent('product', {
              // createComponent expects the NUMERIC product id (as in Shopify's
              // generated snippet); fetchAll returns a Storefront GID / base64.
              id: toNumericId(product.id),
              node,
              moneyFormat: '%24%7B%7Bamount%7D%7D', // ${{amount}}
              options: buyButtonOptions,
            });
          });
          setStatus('ready');
        })
        .catch(() => {
          if (!cancelled) setStatus('error');
        });
    };

    const existing = document.querySelector(`script[src="${BUY_BUTTON_SDK}"]`);
    if ((window as any).ShopifyBuy) {
      buildStore();
    } else if (existing) {
      existing.addEventListener('load', buildStore);
    } else {
      const script = document.createElement('script');
      script.async = true;
      script.src = BUY_BUTTON_SDK;
      script.onload = buildStore;
      script.onerror = () => !cancelled && setStatus('error');
      document.head.appendChild(script);
    }

    return () => {
      cancelled = true;
    };
  }, []);

  return (
    <>
      <MusicNav />
      <main className="shop-page">
        <header className="shop-header">
          <h1>Shop</h1>
          <p>Merch, music &amp; more — shipped worldwide. Secure checkout by Shopify.</p>
        </header>

        {status === 'loading' && <p className="shop-status">Loading products…</p>}
        {status === 'empty' && (
          <p className="shop-status">
            No products are published yet. Check back soon, or visit the{' '}
            <a href={`https://${SHOPIFY_DOMAIN}/`} target="_blank" rel="noopener noreferrer">
              full store
            </a>
            .
          </p>
        )}
        {status === 'error' && (
          <p className="shop-status">
            Couldn’t load the store right now. Visit the{' '}
            <a href={`https://${SHOPIFY_DOMAIN}/`} target="_blank" rel="noopener noreferrer">
              Shopify store
            </a>{' '}
            directly.
          </p>
        )}
        {status === 'unconfigured' && (
          <p className="shop-status">
            Store coming soon. In the meantime, shop at the{' '}
            <a href={`https://${SHOPIFY_DOMAIN}/`} target="_blank" rel="noopener noreferrer">
              Dewpoint store
            </a>
            .
          </p>
        )}

        <div className="shop-grid" ref={gridRef} />
      </main>
      <Footer />
    </>
  );
};

export default ShopPage;
