import React from 'react';
import { Helmet } from 'react-helmet-async';

/**
 * Per-route SEO tags (title / description / canonical / Open Graph / Twitter).
 * react-helmet-async injects these into <head>; react-snap bakes them into the
 * prerendered static HTML so search engines and social scrapers (which don't run
 * JS) see the correct metadata per page.
 */
interface SeoProps {
  title: string;
  description: string;
  path: string;            // route path, e.g. "/epk" ("/" for home)
  image?: string;          // absolute URL or site-relative path; defaults to profile image
  type?: string;           // og:type — "website" | "profile" | "music.musician"
}

const SITE = 'https://dewpoint.live';
const DEFAULT_IMAGE = `${SITE}/og-image.jpg`; // 1200×630 social share card

const Seo: React.FC<SeoProps> = ({ title, description, path, image, type = 'website' }) => {
  const url = `${SITE}${path.startsWith('/') ? path : `/${path}`}`;
  const img = image
    ? (image.startsWith('http') ? image : `${SITE}${image.startsWith('/') ? image : `/${image}`}`)
    : DEFAULT_IMAGE;

  return (
    <Helmet prioritizeSeoTags>
      <title>{title}</title>
      <meta name="description" content={description} />
      <link rel="canonical" href={url} />

      <meta property="og:type" content={type} />
      <meta property="og:site_name" content="Dewpoint" />
      <meta property="og:title" content={title} />
      <meta property="og:description" content={description} />
      <meta property="og:url" content={url} />
      <meta property="og:image" content={img} />
      <meta property="og:image:width" content="1200" />
      <meta property="og:image:height" content="630" />
      <meta property="og:image:alt" content="Dewpoint — audiovisual artist performing live" />

      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={title} />
      <meta name="twitter:description" content={description} />
      <meta name="twitter:image" content={img} />
    </Helmet>
  );
};

export default Seo;
