import React, {
  useState, useEffect, useRef, useCallback,
} from 'react';
import { supabase } from '../lib/supabaseClient';
import './Notebook.css';

// ── Types ────────────────────────────────────────────────────────
type BlockType =
  | 'paragraph' | 'h1' | 'h2' | 'h3'
  | 'todo' | 'bullet' | 'numbered'
  | 'divider' | 'callout' | 'code';

interface Block {
  id: string;
  type: BlockType;
  content: string;
  checked?: boolean;
  color?: string;
}

interface Page {
  id: string;
  project_id: string;
  title: string;
  blocks: Block[];
  thumbnail_url?: string;
  created_at: string;
  updated_at: string;
}

interface Project {
  id: string;
  name: string;
  icon: string;
  thumbnail_url?: string;
  created_at: string;
}

const BLOCK_MENU: { type: BlockType; icon: string; label: string }[] = [
  { type: 'paragraph', icon: '¶',  label: 'Text' },
  { type: 'h1',        icon: 'H1', label: 'Heading 1' },
  { type: 'h2',        icon: 'H2', label: 'Heading 2' },
  { type: 'h3',        icon: 'H3', label: 'Heading 3' },
  { type: 'todo',      icon: '☑',  label: 'To-do' },
  { type: 'bullet',    icon: '•',  label: 'Bullet list' },
  { type: 'numbered',  icon: '1.', label: 'Numbered list' },
  { type: 'callout',   icon: '💡', label: 'Callout' },
  { type: 'code',      icon: '{}', label: 'Code' },
  { type: 'divider',   icon: '—',  label: 'Divider' },
];

function uid() {
  return Math.random().toString(36).slice(2) + Date.now().toString(36);
}

function makeBlock(type: BlockType = 'paragraph'): Block {
  return { id: uid(), type, content: '', checked: false };
}

// ── Component ────────────────────────────────────────────────────
const Notebook: React.FC = () => {
  const [projects,         setProjects]         = useState<Project[]>([]);
  const [pages,            setPages]            = useState<Page[]>([]);
  const [activeProjectId,  setActiveProjectId]  = useState<string | null>(null);
  const [activePageId,     setActivePageId]     = useState<string | null>(null);
  const [sidebarOpen,      setSidebarOpen]      = useState(true);
  const [slashMenu,        setSlashMenu]        = useState<{ blockId: string; filter: string } | null>(null);
  const [editingProject,   setEditingProject]   = useState<string | null>(null);
  const [editingTitle,     setEditingTitle]     = useState(false);
  const [error,            setError]            = useState<string | null>(null);
  const [colorPicker,      setColorPicker]      = useState<string | null>(null);

  const blockRefs     = useRef<Record<string, HTMLTextAreaElement | null>>({});
  const thumbInputRef = useRef<HTMLInputElement | null>(null);
  const thumbTarget   = useRef<{ type: 'project' | 'page'; id: string } | null>(null);
  const saveTimer     = useRef<ReturnType<typeof setTimeout> | null>(null);
  const projInputRef  = useRef<HTMLInputElement | null>(null);
  const titleInputRef = useRef<HTMLInputElement | null>(null);
  const activePage    = pages.find(p => p.id === activePageId) ?? null;

  // Focus project rename input whenever editingProject changes
  useEffect(() => {
    if (editingProject) {
      projInputRef.current?.focus();
      projInputRef.current?.select();
    }
  }, [editingProject]);

  // Focus title input whenever editingTitle turns on
  useEffect(() => {
    if (editingTitle) {
      titleInputRef.current?.focus();
      titleInputRef.current?.select();
    }
  }, [editingTitle]);

  // ── Load ──────────────────────────────────────────────────────
  useEffect(() => {
    (async () => {
      const [{ data: proj }, { data: pgs }] = await Promise.all([
        supabase.from('projects').select('*').order('created_at'),
        supabase.from('pages').select('*').order('created_at'),
      ]);
      const projectList: Project[] = proj ?? [];
      const pageList:    Page[]    = pgs  ?? [];
      setProjects(projectList);
      setPages(pageList);
      if (projectList.length) {
        setActiveProjectId(projectList[0].id);
        const first = pageList.find(p => p.project_id === projectList[0].id);
        if (first) setActivePageId(first.id);
      }
    })();
  }, []);

  // ── Realtime ─────────────────────────────────────────────────
  useEffect(() => {
    const ch = supabase.channel('notebook')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'projects' }, () => {
        supabase.from('projects').select('*').order('created_at')
          .then(({ data }) => { if (data) setProjects(data); });
      })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'pages' }, payload => {
        const ev = payload as any;
        if (ev.eventType === 'DELETE') {
          setPages(prev => prev.filter(p => p.id !== ev.old.id));
        } else {
          setPages(prev => {
            const idx = prev.findIndex(p => p.id === ev.new.id);
            return idx >= 0
              ? prev.map(p => p.id === ev.new.id ? ev.new : p)
              : [...prev, ev.new];
          });
        }
      })
      .subscribe();
    return () => { supabase.removeChannel(ch); };
  }, []);

  // ── Debounced save ────────────────────────────────────────────
  const saveBlocks = useCallback((pageId: string, blocks: Block[]) => {
    if (saveTimer.current) clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(() => {
      supabase.from('pages')
        .update({ blocks, updated_at: new Date().toISOString() })
        .eq('id', pageId)
        .then(() => {});
    }, 400);
  }, []);

  const patchPage = useCallback((pageId: string, blocks: Block[]) => {
    setPages(prev => prev.map(p => p.id === pageId ? { ...p, blocks } : p));
    saveBlocks(pageId, blocks);
  }, [saveBlocks]);

  // ── Thumbnail upload ─────────────────────────────────────────
  const openThumbPicker = (type: 'project' | 'page', id: string) => {
    thumbTarget.current = { type, id };
    thumbInputRef.current?.click();
  };

  const onThumbFile = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !thumbTarget.current) return;
    const { type, id } = thumbTarget.current;
    const ext = file.name.split('.').pop() ?? 'jpg';
    const path = `${type}/${id}.${ext}`;
    const { error: upErr } = await supabase.storage
      .from('thumbnails').upload(path, file, { upsert: true });
    if (upErr) { setError(upErr.message); return; }
    const { data: urlData } = supabase.storage.from('thumbnails').getPublicUrl(path);
    const url = urlData.publicUrl + '?t=' + Date.now();
    if (type === 'project') {
      await supabase.from('projects').update({ thumbnail_url: url }).eq('id', id);
      setProjects(prev => prev.map(p => p.id === id ? { ...p, thumbnail_url: url } : p));
    } else {
      await supabase.from('pages').update({ thumbnail_url: url }).eq('id', id);
      setPages(prev => prev.map(p => p.id === id ? { ...p, thumbnail_url: url } : p));
    }
    e.target.value = '';
  };

  // ── Projects ──────────────────────────────────────────────────
  const createProject = async () => {
    setError(null);
    const { data, error: err } = await supabase.from('projects')
      .insert({ name: 'New Project', icon: '📁' }).select().single();
    if (err || !data) { setError(err?.message ?? 'Failed to create project'); return; }
    setProjects(prev => [...prev, data]);
    setActiveProjectId(data.id);
    setActivePageId(null);
    setEditingProject(data.id);
  };

  const renameProject = async (id: string, name: string) => {
    setProjects(prev => prev.map(p => p.id === id ? { ...p, name } : p));
    await supabase.from('projects').update({ name }).eq('id', id);
  };

  const deleteProject = async (id: string) => {
    await supabase.from('projects').delete().eq('id', id);
    setProjects(prev => prev.filter(p => p.id !== id));
    setPages(prev => prev.filter(p => p.project_id !== id));
    if (activeProjectId === id) {
      setActiveProjectId(null);
      setActivePageId(null);
    }
  };

  // ── Pages ─────────────────────────────────────────────────────
  const createPage = async (projectId: string) => {
    setError(null);
    const { data, error: err } = await supabase.from('pages')
      .insert({ project_id: projectId, title: 'Untitled', blocks: [makeBlock()] })
      .select().single();
    if (err || !data) { setError(err?.message ?? 'Failed to create page'); return; }
    setPages(prev => [...prev, data]);
    setActiveProjectId(projectId);
    setActivePageId(data.id);
    setEditingTitle(true);
  };

  const deletePage = async (id: string) => {
    await supabase.from('pages').delete().eq('id', id);
    setPages(prev => prev.filter(p => p.id !== id));
    if (activePageId === id) setActivePageId(null);
  };

  const saveTitle = async (title: string) => {
    if (!activePageId) return;
    setPages(prev => prev.map(p => p.id === activePageId ? { ...p, title } : p));
    await supabase.from('pages').update({ title }).eq('id', activePageId);
    setEditingTitle(false);
  };

  // ── Block helpers ─────────────────────────────────────────────
  const focusBlock = (id: string, atEnd = true) => {
    setTimeout(() => {
      const el = blockRefs.current[id];
      if (!el) return;
      el.focus();
      if (atEnd) el.setSelectionRange(el.value.length, el.value.length);
    }, 20);
  };

  const addBlockAfter = (afterId: string, type: BlockType = 'paragraph') => {
    if (!activePage) return;
    const nb = makeBlock(type);
    const idx = activePage.blocks.findIndex(b => b.id === afterId);
    const next = [
      ...activePage.blocks.slice(0, idx + 1),
      nb,
      ...activePage.blocks.slice(idx + 1),
    ];
    patchPage(activePage.id, next);
    focusBlock(nb.id);
    return nb.id;
  };

  const updateBlock = (id: string, changes: Partial<Block>) => {
    if (!activePage) return;
    patchPage(activePage.id, activePage.blocks.map(b => b.id === id ? { ...b, ...changes } : b));
  };

  const deleteBlock = (id: string) => {
    if (!activePage) return;
    const blocks = activePage.blocks;
    if (blocks.length === 1) { updateBlock(id, { content: '', type: 'paragraph' }); return; }
    const idx = blocks.findIndex(b => b.id === id);
    const prevId = blocks[Math.max(0, idx - 1)].id;
    patchPage(activePage.id, blocks.filter(b => b.id !== id));
    focusBlock(prevId);
  };

  // ── Keyboard handler ──────────────────────────────────────────
  const onKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>, block: Block) => {
    const ta = e.currentTarget;

    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      setSlashMenu(null);
      addBlockAfter(block.id);
      return;
    }

    if (e.key === 'Backspace' && ta.value === '') {
      e.preventDefault();
      setSlashMenu(null);
      deleteBlock(block.id);
      return;
    }

    if (e.key === 'Escape') { setSlashMenu(null); return; }

    if (e.key === 'ArrowUp' && ta.selectionStart === 0) {
      const blocks = activePage?.blocks ?? [];
      const idx = blocks.findIndex(b => b.id === block.id);
      if (idx > 0) { e.preventDefault(); focusBlock(blocks[idx - 1].id); }
    }

    if (e.key === 'ArrowDown' && ta.selectionEnd === ta.value.length) {
      const blocks = activePage?.blocks ?? [];
      const idx = blocks.findIndex(b => b.id === block.id);
      if (idx < blocks.length - 1) { e.preventDefault(); focusBlock(blocks[idx + 1].id); }
    }
  };

  const onInput = (e: React.FormEvent<HTMLTextAreaElement>, block: Block) => {
    const ta = e.currentTarget;
    ta.style.height = 'auto';
    ta.style.height = ta.scrollHeight + 'px';
    const val = ta.value;

    if (val === '/') {
      setSlashMenu({ blockId: block.id, filter: '' });
      updateBlock(block.id, { content: val });
      return;
    }
    if (slashMenu && slashMenu.blockId === block.id) {
      if (val.startsWith('/')) {
        setSlashMenu({ blockId: block.id, filter: val.slice(1).toLowerCase() });
      } else {
        setSlashMenu(null);
      }
    }
    updateBlock(block.id, { content: val });
  };

  const applySlashType = (type: BlockType) => {
    if (!slashMenu) return;
    updateBlock(slashMenu.blockId, { type, content: '' });
    setSlashMenu(null);
    focusBlock(slashMenu.blockId);
  };

  // ── Render block ──────────────────────────────────────────────
  const COLOR_SWATCHES = [
    { label: 'Default', value: '' },
    { label: 'Gray',    value: '#8b8f9a' },
    { label: 'Red',     value: '#ff6b6b' },
    { label: 'Orange',  value: '#ffa94d' },
    { label: 'Yellow',  value: '#ffd43b' },
    { label: 'Green',   value: '#69db7c' },
    { label: 'Teal',    value: '#38d9a9' },
    { label: 'Blue',    value: '#74c0fc' },
    { label: 'Purple',  value: '#b197fc' },
    { label: 'Pink',    value: '#f783ac' },
  ];

  const renderBlock = (block: Block, idx: number) => {
    const isSlash = slashMenu?.blockId === block.id;
    const isColorOpen = colorPicker === block.id;
    const filtered = isSlash
      ? BLOCK_MENU.filter(m => m.label.toLowerCase().includes(slashMenu!.filter))
      : [];

    const setRef = (el: HTMLTextAreaElement | null) => { blockRefs.current[block.id] = el; };
    const autoGrow = (el: HTMLTextAreaElement | null) => {
      if (el) { el.style.height = 'auto'; el.style.height = el.scrollHeight + 'px'; }
    };

    if (block.type === 'divider') {
      return (
        <div key={block.id} className="nb-block nb-divider-wrap">
          <hr className="nb-divider" />
          <button className="nb-del" onClick={() => deleteBlock(block.id)}>✕</button>
        </div>
      );
    }

    const ta = (
      <textarea
        ref={el => { setRef(el); autoGrow(el); }}
        className={`nb-ta nb-ta-${block.type}`}
        style={block.color ? { color: block.color } : undefined}
        value={block.content}
        placeholder={
          block.type === 'h1' ? 'Heading 1' :
          block.type === 'h2' ? 'Heading 2' :
          block.type === 'h3' ? 'Heading 3' :
          block.type === 'callout' ? 'Callout…' :
          block.type === 'code' ? 'code…' :
          idx === 0 ? "Type '/' for commands…" : ''
        }
        rows={1}
        inputMode="text"
        spellCheck={block.type !== 'code'}
        onKeyDown={e => onKeyDown(e, block)}
        onInput={e => onInput(e, block)}
        onChange={() => {}}
      />
    );

    return (
      <div key={block.id} className={`nb-block nb-block-${block.type}`}>
        {block.type === 'todo' && (
          <span
            className={`nb-check ${block.checked ? 'checked' : ''}`}
            onClick={() => updateBlock(block.id, { checked: !block.checked })}
          >✓</span>
        )}
        {block.type === 'bullet' && <span className="nb-bullet">•</span>}
        {block.type === 'numbered' && (
          <span className="nb-num">{(activePage?.blocks.filter((b, i) => b.type === 'numbered' && i <= activePage.blocks.indexOf(block)).length)}.</span>
        )}
        {block.type === 'callout' && <span className="nb-callout-icon">💡</span>}
        <div className="nb-block-grip">
          {block.type === 'code' ? <div className="nb-code-wrap">{ta}</div> : ta}
          {isSlash && filtered.length > 0 && (
            <div className="nb-slash-menu">
              {filtered.map(m => (
                <button key={m.type} className="nb-slash-item" onMouseDown={() => applySlashType(m.type)}>
                  <span className="nb-slash-icon">{m.icon}</span>
                  <span>{m.label}</span>
                </button>
              ))}
            </div>
          )}
        </div>
        <div className="nb-block-actions">
          <button className="nb-color-btn" title="Text color"
            onClick={() => setColorPicker(isColorOpen ? null : block.id)}>
            <span className="nb-color-dot" style={{ background: block.color || '#e8e9ee' }} />
          </button>
          {isColorOpen && (
            <div className="nb-color-popup">
              {COLOR_SWATCHES.map(s => (
                <button key={s.value} className="nb-swatch" title={s.label}
                  style={{ background: s.value || '#e8e9ee', outline: block.color === s.value ? '2px solid #6ea8fe' : undefined }}
                  onMouseDown={() => { updateBlock(block.id, { color: s.value }); setColorPicker(null); }}
                />
              ))}
              <input type="color" className="nb-color-wheel"
                value={block.color || '#e8e9ee'}
                onInput={e => updateBlock(block.id, { color: (e.target as HTMLInputElement).value })}
                title="Custom color"
              />
            </div>
          )}
          <button className="nb-del" onClick={() => deleteBlock(block.id)}>✕</button>
        </div>
      </div>
    );
  };

  // ── Render ────────────────────────────────────────────────────
  const projectPages = pages.filter(p => p.project_id === activeProjectId);

  return (
    <div className="nb-root" onClick={() => setColorPicker(null)}>
      <input ref={thumbInputRef} type="file" accept="image/*" className="nb-hidden" onChange={onThumbFile} />

      {error && (
        <div className="nb-error-bar">
          ⚠ {error}
          <button onClick={() => setError(null)}>✕</button>
        </div>
      )}
      <div className="nb-inner">
      {/* Sidebar */}
      <aside className={`nb-sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
        <div className="nb-sidebar-head">
          <span className="nb-sidebar-logo">Notebook</span>
          <button className="nb-icon-btn" onClick={() => setSidebarOpen(v => !v)} title="Toggle sidebar">
            {sidebarOpen ? '◀' : '▶'}
          </button>
        </div>

        {sidebarOpen && (
          <>
            <div className="nb-project-list">
              {projects.map(proj => (
                <div key={proj.id} className={`nb-project ${proj.id === activeProjectId ? 'active' : ''}`}>
                  <div className="nb-project-row" onClick={() => {
                    if (proj.id === activeProjectId) {
                      setEditingProject(proj.id);
                    } else {
                      setActiveProjectId(proj.id);
                      const first = pages.find(p => p.project_id === proj.id);
                      if (first) setActivePageId(first.id);
                    }
                  }}>
                    {proj.thumbnail_url
                      ? <img src={proj.thumbnail_url} className="nb-proj-thumb" alt="" />
                      : <span className="nb-proj-icon">{proj.icon}</span>}
                    <button className="nb-thumb-btn" title="Set thumbnail"
                      onMouseDown={e => { e.stopPropagation(); openThumbPicker('project', proj.id); }}>🖼</button>
                    {editingProject === proj.id ? (
                      <input
                        ref={projInputRef}
                        className="nb-proj-input"
                        inputMode="text"
                        defaultValue={proj.name}
                        onBlur={e => { renameProject(proj.id, e.target.value); setEditingProject(null); }}
                        onKeyDown={e => { if (e.key === 'Enter') { renameProject(proj.id, e.currentTarget.value); setEditingProject(null); } if (e.key === 'Escape') setEditingProject(null); }}
                        onClick={e => e.stopPropagation()}
                      />
                    ) : (
                      <span className="nb-proj-name">{proj.name}</span>
                    )}
                    <button className="nb-proj-del" onClick={e => { e.stopPropagation(); deleteProject(proj.id); }} title="Delete project">✕</button>
                  </div>

                  {proj.id === activeProjectId && (
                    <div className="nb-page-list">
                      {pages.filter(p => p.project_id === proj.id).map(pg => (
                        <div
                          key={pg.id}
                          className={`nb-page-item ${pg.id === activePageId ? 'active' : ''}`}
                          onClick={() => setActivePageId(pg.id)}
                        >
                          {pg.thumbnail_url
                            ? <img src={pg.thumbnail_url} className="nb-page-thumb" alt="" />
                            : <span className="nb-page-dot">📄</span>}
                          <span className="nb-page-name">{pg.title || 'Untitled'}</span>
                          <button className="nb-thumb-btn" title="Set thumbnail"
                            onMouseDown={e => { e.stopPropagation(); openThumbPicker('page', pg.id); }}>🖼</button>
                          <button className="nb-proj-del" onClick={e => { e.stopPropagation(); deletePage(pg.id); }} title="Delete page">✕</button>
                        </div>
                      ))}
                      <button className="nb-new-page" onClick={() => createPage(proj.id)}>+ New page</button>
                    </div>
                  )}
                </div>
              ))}
            </div>

            <button className="nb-new-project" onClick={createProject}>+ New project</button>
          </>
        )}
      </aside>

      {/* Editor */}
      <main className="nb-editor">
        {!activePage ? (
          <div className="nb-empty">
            {projects.length === 0
              ? <><p>No projects yet.</p><button className="nb-cta" onClick={createProject}>Create your first project</button></>
              : projectPages.length === 0
              ? <><p>No pages in this project.</p><button className="nb-cta" onClick={() => activeProjectId && createPage(activeProjectId)}>Create a page</button></>
              : <p>Select a page from the sidebar.</p>
            }
          </div>
        ) : (
          <div className="nb-page">
            {activePage.thumbnail_url ? (
              <div className="nb-cover">
                <img src={activePage.thumbnail_url} className="nb-cover-img" alt="" />
                <button className="nb-cover-change" onClick={() => openThumbPicker('page', activePage.id)}>Change cover</button>
              </div>
            ) : (
              <button className="nb-add-cover" onClick={() => openThumbPicker('page', activePage.id)}>+ Add cover</button>
            )}
            {editingTitle ? (
              <input
                ref={titleInputRef}
                className="nb-title-input"
                inputMode="text"
                defaultValue={activePage.title}
                onBlur={e => saveTitle(e.target.value)}
                onKeyDown={e => {
                  if (e.key === 'Enter') saveTitle(e.currentTarget.value);
                  if (e.key === 'Escape') setEditingTitle(false);
                }}
              />
            ) : (
              <h1 className="nb-title" onClick={() => setEditingTitle(true)}>
                {activePage.title || 'Untitled'}
                <span className="nb-title-hint">tap to rename</span>
              </h1>
            )}

            <div className="nb-blocks">
              {(activePage.blocks.length ? activePage.blocks : [makeBlock()]).map((b, i) => renderBlock(b, i))}
            </div>
          </div>
        )}
      </main>
      </div>
    </div>
  );
};

export default Notebook;
