import React from 'react';
import './FloatingSocial.css';

const FloatingSocial: React.FC = () => {
  return (
    <div className="floating-social">
      <div className="social-header">
        <h4>Follow Me</h4>
      </div>
      <div className="social-links">
        <a
          href="https://www.youtube.com/@dewpointlive"
          target="_blank"
          rel="noopener noreferrer"
          className="social-link youtube"
          aria-label="YouTube @dewpointlive"
        >
          <i className="fab fa-youtube"></i>
        </a>

        <a
          href="https://www.instagram.com/dewpoint.live"
          target="_blank"
          rel="noopener noreferrer"
          className="social-link instagram"
          aria-label="Instagram @dewpoint.live"
        >
          <i className="fab fa-instagram"></i>
        </a>

        <a
          href="https://www.tiktok.com/@dewpoint.live"
          target="_blank"
          rel="noopener noreferrer"
          className="social-link tiktok"
          aria-label="TikTok @dewpoint.live"
        >
          <i className="fab fa-tiktok"></i>
        </a>

        <a
          href="https://artstation.com/dewpoint"
          target="_blank"
          rel="noopener noreferrer"
          className="social-link artstation"
          aria-label="ArtStation"
        >
          <i className="fas fa-palette"></i>
        </a>
      </div>
    </div>
  );
};

export default FloatingSocial;
