import React from 'react';
import './Contact.css';

const Contact: React.FC = () => {
  

  const contactInfo = [
    {
      icon: 'fas fa-envelope',
      title: 'Email',
      value: 'anthony@dewpoint.live',
      link: 'mailto:anthony@dewpoint.live'
    },
    {
      icon: 'fas fa-map-marker-alt',
      title: 'Location',
      value: 'Various Locations',
      link: '#'
    },
    {
      icon: 'fas fa-clock',
      title: 'Availability',
      value: 'Event-based scheduling',
      link: '#'
    }
  ];

  const socialLinks = [
    {
      icon: 'fas fa-palette',
      name: 'Portfolio',
      url: 'https://artstation.com/dewpoint',
      color: '#00ff88'
    },
    {
      icon: 'fab fa-linkedin',
      name: 'LinkedIn',
      url: 'https://linkedin.com',
      color: '#0077b5'
    },
    {
      icon: 'fab fa-instagram',
      name: 'Instagram',
      url: 'https://instagram.com',
      color: '#e4405f'
    },
    {
      icon: 'fab fa-youtube',
      name: 'YouTube',
      url: 'https://youtube.com',
      color: '#ff0000'
    }
  ];

  return (
    <section id="contact" className="section contact">
      <div className="container">
        <h2 className="section-title">Get In Touch</h2>
        
        <div className="contact-intro">
          <p>
            I'm always interested in hearing about new event opportunities and exciting audio-visual projects. 
            Whether you have a question about event production or just want to say hi, feel free to reach out!
          </p>
        </div>

        <div className="contact-content">
          <div className="contact-info">
            <h3>Let's Connect</h3>
            <p>
              I'm currently available for event production work and freelance audio-visual opportunities. 
              If you have an event that needs professional audio-visual support, I'd love to hear about it.
            </p>
            
            <div className="contact-details">
              {contactInfo.map((info, index) => (
                <div key={index} className="contact-item">
                  <div className="contact-icon">
                    <i className={info.icon}></i>
                  </div>
                  <div className="contact-text">
                    <h4>{info.title}</h4>
                    <a href={info.link} target="_blank" rel="noopener noreferrer">
                      {info.value}
                    </a>
                  </div>
                </div>
              ))}
            </div>

            {/* Old "Follow Me" section removed - now handled by floating social component */}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Contact; 