import React, { useEffect, useState } from 'react';
import { Helmet } from 'react-helmet-async';
import './TourCalendar.css';

const SITE = 'https://dewpoint.live';

// schema.org MusicEvent JSON-LD for each upcoming show → eligible for Google event rich results.
function buildEventsJsonLd(shows: Show[]): string {
  const events = shows.map(s => {
    const ev: Record<string, unknown> = {
      '@context': 'https://schema.org',
      '@type': 'MusicEvent',
      name: `Dewpoint at ${s.venue}`,
      startDate: s.date,
      eventStatus: 'https://schema.org/EventScheduled',
      eventAttendanceMode: 'https://schema.org/OfflineEventAttendanceMode',
      location: {
        '@type': 'Place',
        name: s.venue,
        address: {
          '@type': 'PostalAddress',
          addressLocality: s.city,
          addressRegion: s.state || undefined,
          addressCountry: 'US',
        },
      },
      performer: { '@type': 'MusicGroup', name: 'Dewpoint', '@id': `${SITE}/#dewpoint` },
      organizer: { '@type': 'MusicGroup', name: 'Dewpoint', url: `${SITE}/` },
      image: s.thumbnail ? `${SITE}/${s.thumbnail}` : `${SITE}/profile-image.jpg`,
      url: s.ticketUrl || `${SITE}/`,
    };
    if (s.ticketUrl) {
      ev.offers = { '@type': 'Offer', url: s.ticketUrl, availability: 'https://schema.org/InStock' };
    }
    return ev;
  });
  return JSON.stringify(events);
}

interface Show {
  id: number;
  date: string;
  venue: string;
  city: string;
  state: string;
  ticketUrl: string;
  ticketLabel?: string;
  note?: string;
  thumbnail?: string;
  status: 'upcoming' | 'past';
}

function formatDate(dateStr: string): string {
  const d = new Date(dateStr + 'T00:00:00');
  return new Intl.DateTimeFormat('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  }).format(d);
}

const TourCalendar: React.FC = () => {
  const [shows, setShows] = useState<Show[]>([]);

  useEffect(() => {
    fetch('/shows.json')
      .then(r => (r.ok ? r.json() : []))
      .then(setShows)
      .catch(() => {});
  }, []);

  const upcoming = shows.filter(s => s.status === 'upcoming');

  return (
    <section className="tour-calendar section" id="tour">
      {upcoming.length > 0 && (
        <Helmet>
          <script type="application/ld+json">{buildEventsJsonLd(upcoming)}</script>
        </Helmet>
      )}
      <div className="container">
        <h2 className="section-title tour-title">Tour Dates</h2>

        <div className="shows-list">
          {upcoming.length === 0 ? (
            <div className="shows-empty">
              No upcoming shows announced — check back soon.
            </div>
          ) : (
            upcoming.map(show => (
              <div className={`show-row${show.thumbnail ? ' has-thumbnail' : ''}`} key={show.id}>
                {show.thumbnail && (
                  <div className="show-thumbnail">
                    <img src={`/${show.thumbnail}`} alt={`${show.venue} flyer`} loading="lazy" />
                  </div>
                )}
                <div className="show-date">{formatDate(show.date)}</div>
                <div className="show-venue">
                  <span className="show-venue-name">{show.venue}</span>
                  <span className="show-location">
                    {show.city}{show.state ? `, ${show.state}` : ''}
                    {show.note ? ` · ${show.note}` : ''}
                  </span>
                </div>
                <div className="show-actions">
                  {show.ticketUrl && (
                    <a
                      href={show.ticketUrl}
                      className="ticket-btn"
                      target="_blank"
                      rel="noopener noreferrer"
                    >
                      {show.ticketLabel || 'Tickets'}
                    </a>
                  )}
                </div>
              </div>
            ))
          )}
        </div>

        <div className="tour-follow">
          <a
            className="bit-follow-btn"
            href="https://www.bandsintown.com/a/15582559"
            target="_blank"
            rel="noopener noreferrer"
          >
            <i className="fas fa-bell" aria-hidden="true"></i>
            Follow on Bandsintown
          </a>
          <span className="tour-follow-note">Get alerts the moment new shows drop.</span>
        </div>
      </div>
    </section>
  );
};

export default TourCalendar;
