import React, { useState } from 'react';
import './NewsletterSignup.css';

// Posts directly to Kit's (ConvertKit) public form-subscriptions endpoint — the same
// endpoint their own embed script uses. No secret key required: the numeric form ID
// is safe to expose client-side, same as it would be in a plain HTML embed.
const KIT_FORM_ID = process.env.REACT_APP_KIT_FORM_ID;

type Status = 'idle' | 'loading' | 'success' | 'error';

const NewsletterSignup: React.FC = () => {
  const [email, setEmail] = useState('');
  const [status, setStatus] = useState<Status>('idle');
  const [message, setMessage] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!KIT_FORM_ID) {
      setStatus('error');
      setMessage('Signup is not configured yet — check back soon.');
      return;
    }

    setStatus('loading');
    setMessage('');

    try {
      const res = await fetch(`https://app.kit.com/forms/${KIT_FORM_ID}/subscriptions`, {
        method: 'POST',
        headers: {
          Accept: 'application/json',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({ email_address: email }),
      });

      const data = await res.json().catch(() => null);

      if (res.ok && data?.status !== 'error') {
        setStatus('success');
        setMessage('You’re in — check your inbox to confirm.');
        setEmail('');
      } else {
        setStatus('error');
        setMessage(data?.errors?.[0] || 'Something went wrong — try again in a bit.');
      }
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error('Newsletter signup failed (often an ad blocker blocking kit.com):', err);
      setStatus('error');
      setMessage('Network error — try again in a bit.');
    }
  };

  return (
    <section className="newsletter-signup section" id="newsletter">
      <div className="container newsletter-container">
        <h2 className="section-title newsletter-title">Stay Updated</h2>

        {status === 'success' ? (
          <p className="newsletter-success">{message}</p>
        ) : (
          <form className="newsletter-form" onSubmit={handleSubmit}>
            <label htmlFor="newsletter-email" className="sr-only">
              Email address
            </label>
            <input
              id="newsletter-email"
              type="email"
              required
              placeholder="you@example.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              disabled={status === 'loading'}
              className="newsletter-input"
            />
            <button
              type="submit"
              className="newsletter-submit"
              disabled={status === 'loading'}
            >
              {status === 'loading' ? 'Joining…' : 'Subscribe'}
            </button>
          </form>
        )}

        {status === 'error' && <p className="newsletter-error">{message}</p>}
      </div>
    </section>
  );
};

export default NewsletterSignup;
